<script>
import DataService from '../../services/DataService';
export default {
    components: {

    },
    props: {
        deviceRecord: {
            type: Object,
            default: () => ({})
        }
    },
    data() {
        return {
            activeTab: 'details',
            syncLogs: [
                { time: "2023-10-15 14:05:00", message: "Data synchronization completed", status: "success" },
                { time: "2023-10-15 13:50:00", message: "Visitor logs uploaded", status: "success" },
                { time: "2023-10-15 13:35:00", message: "Cache cleared and rebuilt", status: "success" }
            ],
            deviceForm: {
                deviceName: '',
                uniqueCode: '',
                deviceModel: '',
                subLocation: '',
                apiUrl: '',
                syncFrequency: "Daily",
                statusId: null
            },
            scheduleTimes: [
                { time: '' }
            ],
            Headers: [
                {
                    COLUMN_NAME: "name",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: "Schedule Name",
                    DISPLAY_ORDER: 1,
                    settings: { isInSlot: false },
                },
                {
                    COLUMN_NAME: "time",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: "Time",
                    DISPLAY_ORDER: 1,
                    settings: { isInSlot: false },
                },
                {
                    COLUMN_NAME: "action",
                    DATA_TYPE: "text",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: "Action",
                    DISPLAY_ORDER: 3,
                    settings: { isInSlot: true },
                }
            ],
            errors: {}

        };
    },
    mounted() {
        console.log("deviceRecord",);
        // Example existing device data

        this.scheduleTimes = [{ name: "Test", time: '2023-10-15 14:05:00' }, { name: "Test 2", time: "2023-10-15 17:05:00" }];

        this.deviceForm = { ...this.deviceRecord };
    },
    methods: {
        addSchedule() {
            this.scheduleTimes.push({ time: '' });
        },

        removeSchedule(index) {
            this.scheduleTimes.splice(index, 1);
        },
        handleClose() {
            this.$emit("close");
        },
        validateScheduleTimes() {
            for (const item of this.scheduleTimes) {
                if (!item.time) {
                    return 'Date and time are required';
                }
            }

            return null;
        },
        validateForm() {
            this.errors = {};

            if (!this.deviceForm.deviceName) {
                this.errors.deviceName = 'Device name is required';
            }
            if (!this.deviceForm.uniqueCode) {
                this.errors.uniqueCode = 'Device ID is required';
            }
            if (!this.deviceForm.subLocation) {
                this.errors.subLocation = 'Location is required';
            }
            if (!this.deviceForm.apiUrl) {
                this.errors.apiUrl = 'Face Auth URL is required';
            } else if (!/^https?:\/\//i.test(this.deviceForm.apiUrl)) {
                this.errors.apiUrl = 'Invalid URL format';
            }
            return Object.keys(this.errors).length === 0;
        },
        clearError(field) {
            if (this.errors[field]) {
                this.$delete(this.errors, field);
            }
        },
        forceRun(row) {
            this.$socket.emit('forcefullyRun', { deviceId: this.deviceForm.uniqueCode });
            this.ShowAlert(
                    this.$t("syncProcessInitiated"),
                    'success',
                    true,
                    this.$t('Alert')
                );

        },
        async submitForm() {
            if (!this.validateForm()) {
                this.activeTab = 'details';
                return;
            }

            try {
                const result = await DataService.DeviceRegister(this.deviceForm);
                // Emit success result
                this.$emit('submitRecord', this.deviceForm);
                this.ShowAlert(
                    this.$t("Deviceupdatedsuccessfully"),
                    'success',
                    true,
                    this.$t('Alert')
                );
            } catch (error) {
                //console.error("Device update failed:", error);
                // Optional: show API error message if available
                const message =
                    error?.response?.data?.message ||
                    this.$t("ErrorWhileProcessingRequest");
                this.ShowAlert(
                    message,
                    'error',
                    true,
                    this.$t('Alert')
                );
            }
        }
    }
}
</script>
